import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class Main {
  public static void main(String[] args) {
    List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
    List<Integer> evenDoubled = numbers.stream()
                                       .filter(n -> n % 2 == 0)
                                       .map(n -> n * 2)
                                       .collect(Collectors.toList());
    System.out.println("Cüt ədədlər ikiqat: " + evenDoubled);
  }
}
// Çıxış: Cüt ədədlər ikiqat: [4, 8]

import java.util.Arrays;
import java.util.List;

public class Main {
  public static void main(String[] args) {
    List<String> names = Arrays.asList("Ali", "Veli", "Ayşe", "Fatma");
    names.stream()
         .filter(name -> name.startsWith("A"))
         .forEach(name -> System.out.println("Ad: " + name));
  }
}
// Çıxış:
// Ad: Ali
// Ad: Ayşe

